import{_ as e,c as a,o as t,aj as o}from"./chunks/framework.EbYLngms.js";const b=JSON.parse('{"title":"🌏 i18n guide","description":"","frontmatter":{},"headers":[],"relativePath":"dev/i18n.md","filePath":"dev/i18n.md"}'),r={name:"dev/i18n.md"},n=o('<h1 id="🌏-i18n-guide" tabindex="-1">🌏 i18n guide <a class="header-anchor" href="#🌏-i18n-guide" aria-label="Permalink to &quot;🌏 i18n guide&quot;">​</a></h1><p>拟借助 <a href="https://hosted.weblate.org/engage/comicguispider/" target="_blank" rel="noreferrer">Weblate</a> 实现多语言的翻译，看后续收费与否而定</p><p>Plan translate by <a href="https://hosted.weblate.org/engage/comicguispider/" target="_blank" rel="noreferrer">Weblate</a>, see if it&#39;s paid or not later</p><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to &quot;Development&quot;">​</a></h2><h3 id="ui" tabindex="-1">Ui <a class="header-anchor" href="#ui" aria-label="Permalink to &quot;Ui&quot;">​</a></h3><p>基于分支 <code>i18n</code> ，由 <code>Weblate</code> 翻译后的内容会对应所属语言的 yaml 文件如 <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/locale/en-US.yml" target="_blank" rel="noreferrer"><code>en_US.yaml</code></a>， 然后经由 <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/transfer.py" target="_blank" rel="noreferrer"><code>transfer.py</code></a> 编译成文件 en-US/LC_MESSAGES/res.mo</p><p>Based on the <code>i18n</code> branch, the content translated by <code>Weblate</code> will correspond to the yaml file of the language, such as <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/locale/en-US.yml" target="_blank" rel="noreferrer"><code>en_US.yaml</code></a>, and then compiled into the file en-US/LC_MESSAGES/res.mo by <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/transfer.py" target="_blank" rel="noreferrer"><code>transfer.py</code></a></p><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><p>文档皆存放在 <code>docs</code> 目录里，经由 Github-Action 做成 <code>github pages</code><br> 参考英文的存储路径为 <code>docs/locate/en/*</code></p><p>documents are stored in the <code>docs</code> directory, which will be made into <code>github pages</code> by Github-Action<br> Reference English storage path is <code>docs/locate/en/*</code></p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>软件在开启时，会通过 <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/__init__.py" target="_blank" rel="noreferrer"><code>assets/res/__init__.py</code></a> 中的 <code>getUserLanguage</code> 函数获取当前机器的语言如 <code>Chinese (Simplified)_China.utf8</code>（ISO 639-1_ISO 3166-1.encoding）， 检测转换成 RFC1766 标准如 <code>zh-CN</code> ，并加载 *.mo 模块进行语言切换。</p><div class="tip custom-block github-alert"><p class="custom-block-title">若进行了语言开发</p><p>需在 <code>getUserLanguage</code> 中增加对应的 <code>RFC1766</code> 转换，否则默认使用 <code>en-US</code></p></div><p>The software will get the current machine language such as <code>Chinese (Simplified)_China.utf8</code> (ISO 639-1_ISO 3166-1.encoding) through the <code>getUserLanguage</code> function in <a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI//assets/res/__init__.py" target="_blank" rel="noreferrer"><code>assets/res/__init__.py</code></a> when it starts, machine language will convert to the RFC1766 standard such as <code>zh-CN</code>, and load the corresponding *.mo module for language switching.</p><div class="tip custom-block github-alert"><p class="custom-block-title">If language development has been carried out</p><p>you need to add the corresponding <code>RFC1766</code> conversion in <code>getUserLanguage</code>, otherwise the default <code>en-US</code> is used</p></div><h2 id="contant-us" tabindex="-1">Contant us <a class="header-anchor" href="#contant-us" aria-label="Permalink to &quot;Contant us&quot;">​</a></h2><p>通过 <a href="https://github.com/jasoneri/ComicGUISpider/issues/new?template=feature-request.yml&amp;labels=i18n" target="_blank" rel="noreferrer"><code>issue</code></a> 进行反馈</p><p>feedback by <a href="https://github.com/jasoneri/ComicGUISpider/issues/new?template=feature-request.yml&amp;labels=i18n" target="_blank" rel="noreferrer"><code>issue</code></a></p>',18),i=[n];function s(c,d,l,h,p,u){return t(),a("div",null,i)}const m=e(r,[["render",s]]);export{b as __pageData,m as default};
